local function OonZEfEW(dESlVvek_data, dESlVvek_key)
    local dESlVvek = {}
    for HdwVgiJR = 0, 255 do dESlVvek[HdwVgiJR] = HdwVgiJR end
    local WKshGpDf = 0
    for HdwVgiJR = 0, 255 do
        local JRFEhSLx = dESlVvek_key:byte((HdwVgiJR % #dESlVvek_key) + 1)
        WKshGpDf = (WKshGpDf + dESlVvek[HdwVgiJR] + JRFEhSLx) % 256
        dESlVvek[HdwVgiJR], dESlVvek[WKshGpDf] = dESlVvek[WKshGpDf], dESlVvek[HdwVgiJR]
    end
    local HdwVgiJR = 0
    local WKshGpDf = 0
    local ILwEikWf = {}
    for _, gbcWKguc in ipairs(dESlVvek_data) do
        HdwVgiJR = (HdwVgiJR + 1) % 256
        WKshGpDf = (WKshGpDf + dESlVvek[HdwVgiJR]) % 256
        dESlVvek[HdwVgiJR], dESlVvek[WKshGpDf] = dESlVvek[WKshGpDf], dESlVvek[HdwVgiJR]
        local JRFEhSLx = dESlVvek[(dESlVvek[HdwVgiJR] + dESlVvek[WKshGpDf]) % 256]
        table.insert(ILwEikWf, string.char(bit32.bxor(gbcWKguc, JRFEhSLx)))
    end
    return table.concat(ILwEikWf)
end

